(self.webpackChunkblog_vuepress=self.webpackChunkblog_vuepress||[]).push([[69],{3329:(l,p,i)=>{"use strict";i.r(p),i.d(p,{data:()=>e});const e={key:"v-1c6cce2f",path:"/technology/MATLAB%20%E5%A4%8D%E4%B9%A0.html",title:"MATLAB 复习",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"基础",slug:"基础",children:[]},{level:2,title:"函数复习",slug:"函数复习",children:[]},{level:2,title:"运算复习",slug:"运算复习",children:[]},{level:2,title:"流程控制",slug:"流程控制",children:[]},{level:2,title:"文件",slug:"文件",children:[]}],filePathRelative:"technology/MATLAB 复习.md",git:{updatedTime:1626432089e3}}},3312:(l,p,i)=>{"use strict";i.r(p),i.d(p,{default:()=>t});const e=(0,i(6252).uE)('<h1 id="matlab-复习" tabindex="-1"><a class="header-anchor" href="#matlab-复习" aria-hidden="true">#</a> MATLAB 复习</h1><h2 id="基础" tabindex="-1"><a class="header-anchor" href="#基础" aria-hidden="true">#</a> 基础</h2><hr><ul><li>A = [1,2,3; 4,5,6; 7,8,9]</li><li>初始值 : 步长 : 终止值 <em>(其中包括起始值和终止值)</em></li><li>字符串用==单引号==括起来（ &#39; 用两个单引号 &#39;&#39; 转义）</li></ul><h2 id="函数复习" tabindex="-1"><a class="header-anchor" href="#函数复习" aria-hidden="true">#</a> 函数复习</h2><hr><ul><li><p>linspace(x, y, z) : 生成行向量 ( x 为首元素，y 为末元素，z 为个数)</p></li><li><p>reshape(A, m, n) : 改变矩阵形状</p></li><li><p>rem (a, b) : 取余</p></li><li><p>fix (a) : 向==零方向==取整</p></li><li><p>floor(a) : 向==负无穷方向==取整</p></li><li><p>ceil(a) : 向==正无穷方向==取整</p></li><li><p>log(a) : ==自然对数==</p></li><li><p>exp(a) : 自然指数</p></li><li><p>find(a) : 找非零元素的位置</p></li><li><p>length(a) : 求长度</p></li><li><p>==zeros(a) : 产生全 0 矩阵==</p></li><li><p>==ones(a) : 产生全 1 矩阵==</p></li><li><p>==eye(a) : 单位阵==</p></li><li><p>rand(num) : 产生 (0, 1) 区间均匀分布的随机矩阵，num为阶数</p><ul><li>eg : x = 20+(50-20)*rand(5)</li></ul></li><li><p>diag(A[ , num]) : 提取矩阵的对角线元素；构造对角阵</p><ul><li>提取主对角线元素形成列向量，主对角线以上记为正数，以下记为负数，num 即为哪条对角线</li><li>构造对角阵同理，但 A 必须要为行向量</li></ul></li><li><p>triu(A[ , num]) : 上三角阵，与上同理</p></li><li><p>tril(A[ , num]) : 下三角阵，与上同理</p></li><li><p>A&#39; : 共轭转置</p></li><li><p>A.&#39; : 转置 （实数范围内，共轭转置和转置结果一样）</p></li><li><p>==inv(A) : 矩阵求逆==</p></li><li><p>==det(A) : 求方阵对应行列式的值==</p></li><li><p>==rank(A) : 矩阵求秩==</p></li><li><p>==trace(A) : 矩阵求迹==（迹为矩阵对角线元素之和，也等于矩阵的特征值之和）</p></li><li><p>norm(V[ , 1 / 2 or null / inf ]) : 求 1-范数，2-范数和无穷大范数</p></li><li><p>cond(A[ , 1 / 2 or null / inf ]) : 求在 1-范数，2-范数和无穷大范数下的条件数</p></li><li><p>eig(A) : 求矩阵的全部特征向量</p></li><li><p>A = input ( &#39;提示信息&#39; [, &#39;s&#39; ]);</p><ul><li>如果要输入字符串就加上后面的 &#39;s&#39; 选项</li></ul></li><li><p>disp(a) : 输出内容</p></li><li><p>pause(延迟秒数) : 暂停程序</p></li><li><p>==plot(x, y)== : 以 x, y 为横纵坐标绘制二维曲线，其中 x, y 为长度相同的向量</p><ul><li><p>当 x, y 为同型矩阵时，则以 x, y 对应列元素为横纵坐标绘制，曲线条数等于矩阵列数</p></li><li><p>可以输入多组 x, y 以绘制多条曲线，跟在前一组可选参数后面</p></li><li><p>可选参数：</p><blockquote><p>-                                     -.                                    :                               --</p><p>实线（默认值） 点画线 虚线 双划线</p></blockquote><blockquote><p>b (blue) 蓝色</p><p>g (green) 绿色</p><p>r (red) 红色</p><p>c (cyan) 青色</p><p>m (magenta) 品红</p><p>y (yellow) 黄色</p><p>k (black) 黑色</p><p>w (white) 白色</p></blockquote><blockquote><p>. 点</p><p>o (字母) 圆圈</p><p>x (字母) 叉号</p><p>+                             加号</p><p>*                              星号</p><p>s ( square ) 方块</p><p>d ( diamond ) 菱形</p><p>v (字母) 朝下三角</p><p>^ 朝上三角</p><p>&lt; 朝左三角</p><p>&gt;                             朝右三角</p><p>p ( pentagram ) 五角星</p><p>h ( hexagram ) 六角星</p></blockquote></li></ul></li><li><p>plotyy(x1, y1, x2, y2) : 双纵坐标函数</p></li><li><p>title(图形名称) 图形标注</p></li><li><p>xlabel(x 轴说明) 图形标注</p></li><li><p>ylabel(y 轴说明) 图形标注</p></li><li><p>text(x, y, 图形说明) 图形标注</p></li><li><p>legend(图例1, 图例2, ...) 图形标注，图例即介绍线型和作用的，类似于地图</p></li><li><blockquote><p>hold on;</p><p>hold off;</p><p>作用即控制是否保持原有图形还是刷新原有图形</p></blockquote></li><li><p>subplot(m, n, p) : 将窗口分割成 m x n 个绘图区，m 行，每行 n 个，依次编号，选中第 p 个区域</p></li><li><p>fplot(filename, lims, 选项) : 自适应采样绘图</p><ul><li>filename : 代表一个函数，通常采用函数句柄的形式，也可以是字符串形式</li><li>lims : x 轴的取值范围，取二元向量 [xmin, xmax] , 默认值为 [-5, 5]</li></ul></li><li><p>polar(theta, rho, 选项) : 极坐标绘图</p><ul><li>theta : 极坐标极角</li><li>rho : 极坐标极径</li></ul></li><li><p>==其他形式二维图形暂不列出==</p></li><li><p>plot3(x, y, z, 选项) : 绘制三维曲线</p></li><li><blockquote><p>三维曲面绘制函数</p></blockquote><ul><li>meshgrid(x, y) : 生成平面网格坐标矩阵，其中 x, y 为冒号表达式或者行向量</li><li>mesh(x, y, z, c) : x, y, z 为同型矩阵，x, y 是网格坐标矩阵，z 是网格高度矩阵，c 为色标矩阵用于指定曲面颜色，c有默认值，输入时可以不予指定。在不需要绘制特别精细的三维曲面图时，可以通过三维网格图表示三维曲面</li><li>surf(x, y, z, c) : x, y, z, c 与上同理，各线条之间的补面用颜色填充</li></ul></li><li><p>==其他形式三维图形暂不列出==</p></li><li><p>ezplot(f [, a, b] ) : f 为一个函数 y=f(x) ，可选参数 a, b 为 x 的区间，如果要设定 y 的区间，跟在 x 的区间后面即可，默认区间为 -2π &lt; x &lt; 2π 。其中 f 可以为函数文件名或者函数表达式组成的字符串</p></li></ul><h2 id="运算复习" tabindex="-1"><a class="header-anchor" href="#运算复习" aria-hidden="true">#</a> 运算复习</h2><hr><ul><li><ul><li></li></ul></li><li><ul><li></li></ul></li><li><ul><li></li></ul></li><li>\\ （左除）</li><li>/ （右除）</li><li>&lt;</li><li>&lt;=</li><li>&gt;</li><li>&gt;=</li><li>==</li><li>~= （不等于）</li><li>^ （乘方）</li><li>&amp;</li><li>|</li><li>~</li><li>xor （异或）</li><li><em>点运算</em></li></ul><h2 id="流程控制" tabindex="-1"><a class="header-anchor" href="#流程控制" aria-hidden="true">#</a> 流程控制</h2><hr><ul><li><p>if 结构：</p><blockquote><p>if 条件</p><p>​ 语句组</p><p>end</p></blockquote><blockquote><p>if 条件</p><p>​ 语句组1</p><p>else</p><p>​ 语句组2</p><p>end</p></blockquote><blockquote><p>if 条件1</p><p>​ 语句组1</p><p>elseif 条件2</p><p>​ 语句组2</p><p>​ ……</p><p>else</p><p>​ 语句组n</p><p>end</p></blockquote><p>不需要像 python 那样条件后面跟冒号，也不需要大括号，最后要有 end 标识。</p></li><li><p>switch 结构：</p><blockquote><p>switch 表达式</p><p>​ case 结果表1</p><p>​ 语句组1</p><p>​ case 结果表2</p><p>​ 语句组2</p><p>​ ……</p><p>​ case 结果表n</p><p>​ 语句组n</p><p>​ otherwise</p><p>​ 语句组n</p><p>end</p></blockquote></li><li><p>for 结构：</p><blockquote><p>for 循环变量=表达式1 : 表达式2 : 表达式3</p><p>​ 循环体语句</p><p>end</p></blockquote><p>表达式块为一个冒号表达式，产生一个行向量，如果有行向量矩阵可供直接使用，那么将同该行向量的效果一样，将行向量里的每一个元素代入到循环体语句中执行，知道该行向量元素循环完毕。</p></li><li><p>while 结构：</p><blockquote><p>while 条件</p><p>​ 循环体语句</p><p>end</p></blockquote></li><li><p>break 和 continue ：与其他编程语言中效果相同</p></li></ul><h2 id="文件" tabindex="-1"><a class="header-anchor" href="#文件" aria-hidden="true">#</a> 文件</h2><hr><ul><li><p>格式：</p><blockquote><p>function 输出形参表=函数名(输入形参表)</p><p>​ 注释说明部分</p><p>​ 函数体语句</p></blockquote></li><li><p>函数文件名一般跟函数名相同。如果不一致，调用则直接使用函数名；</p></li><li><p>有 return 语句；</p></li><li><p>有递归调用；</p></li><li><p>匿名函数格式：</p><blockquote><p>函数句柄变量=@(匿名函数输入参数) 匿名函数表达式</p><p>函数句柄变量：相当于函数别名，可以通过其间接调用函数</p><p>@：创建函数句柄的运算符</p></blockquote></li></ul>',16),t={render:function(l,p){return e}}}}]);